import type { Meta, StoryObj } from '@storybook/react-vite';
import { Alert } from './Alert';
import { Space } from '../Space';

const meta = {
  title: 'Components/Alert',
  component: Alert,
  tags: ['autodocs'],
  argTypes: {
    title: { control: 'text' },
    type: { control: 'inline-radio', options: ['success', 'warning', 'info', 'error'] },
    description: { control: 'text' },
    effect: { control: 'inline-radio', options: ['light', 'dark'] },
    closable: { control: 'boolean' },
    closeText: { control: 'text' },
    center: { control: 'boolean' },
    showIcon: { control: 'boolean' },
    onClose: { control: false },
  },
  args: {
    title: 'Heads up',
    type: 'info',
    closable: true,
    showIcon: true,
  },
} satisfies Meta<typeof Alert>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => <Alert {...args} />,
};

export const Types: Story = {
  render: () => (
    <Space direction="vertical" alignment="start" style={{ width: 360 }}>
      <Alert title="Operation succeeded" type="success" showIcon />
      <Alert title="Check your input" type="warning" showIcon />
      <Alert title="For your information" type="info" showIcon />
      <Alert title="Something failed" type="error" showIcon />
    </Space>
  ),
};

export const WithDescription: Story = {
  name: 'With a description',
  render: () => (
    <Space direction="vertical" alignment="start" style={{ width: 360 }}>
      <Alert
        title="Update available"
        type="info"
        showIcon
        description="A new version of the app is ready. Reload to apply the latest changes."
      />
      <Alert
        title="Payment failed"
        type="error"
        showIcon
        description="We could not charge your card. Update your billing details to continue."
      />
    </Space>
  ),
};

export const DarkEffect: Story = {
  name: 'Dark effect',
  render: () => (
    <Space direction="vertical" alignment="start" style={{ width: 360 }}>
      <Alert title="Success" type="success" effect="dark" showIcon />
      <Alert title="Warning" type="warning" effect="dark" showIcon />
      <Alert title="Error" type="error" effect="dark" showIcon />
    </Space>
  ),
};

import {
  forwardRef,
  type HTMLAttributes,
  type MouseEvent,
  type ReactNode,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type AlertType = 'success' | 'warning' | 'info' | 'error';

export type AlertEffect = 'light' | 'dark';

export interface AlertProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  /** Title text. */
  title?: ReactNode;
  /** Visual variant. Default `'info'`. */
  type?: AlertType;
  /** Descriptive content beneath the title. Falls back to `children`. */
  description?: ReactNode;
  /** Show the close affordance. Default `true`. */
  closable?: boolean;
  /** Custom text for the close affordance (replaces the close icon). */
  closeText?: string;
  /** Center the title text. */
  center?: boolean;
  /** Theme intensity. Default `'light'`. */
  effect?: AlertEffect;
  /** Show the leading type icon. Default `false`. */
  showIcon?: boolean;
  /** Fired when the alert is closed. */
  onClose?: (e: MouseEvent) => void;
  children?: ReactNode;
}

const ICON_PATHS: Record<AlertType, string> = {
  // success: filled circle with a check
  success:
    'M12 2a10 10 0 1 0 0 20 10 10 0 0 0 0-20zm-1.1 14.2-3.6-3.6 1.4-1.4 2.2 2.2 4.8-4.8 1.4 1.4-6.2 6.2z',
  // warning: triangle with an exclamation mark
  warning:
    'M12 2 1 21h22L12 2zm1 14h-2v2h2v-2zm0-7h-2v5h2V9z',
  // info: filled circle with a lowercase i
  info: 'M12 2a10 10 0 1 0 0 20 10 10 0 0 0 0-20zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z',
  // error: filled circle with a cross
  error:
    'M12 2a10 10 0 1 0 0 20 10 10 0 0 0 0-20zm5 13.59L15.59 17 12 13.41 8.41 17 7 15.59 10.59 12 7 8.41 8.41 7 12 10.59 15.59 7 17 8.41 13.41 12 17 15.59z',
};

function TypeIcon({ type, className }: { type: AlertType; className: string }) {
  return (
    <svg
      className={className}
      viewBox="0 0 24 24"
      width="1em"
      height="1em"
      aria-hidden="true"
      focusable="false"
    >
      <path fill="currentColor" d={ICON_PATHS[type]} />
    </svg>
  );
}

function CloseIcon() {
  return (
    <svg viewBox="0 0 24 24" width="1em" height="1em" aria-hidden="true" focusable="false">
      <path
        fill="currentColor"
        d="M13.41 12l5.3-5.29a1 1 0 1 0-1.42-1.42L12 10.59l-5.29-5.3a1 1 0 0 0-1.42 1.42l5.3 5.29-5.3 5.29a1 1 0 0 0 0 1.42 1 1 0 0 0 1.42 0L12 13.41l5.29 5.3a1 1 0 0 0 1.42 0 1 1 0 0 0 0-1.42z"
      />
    </svg>
  );
}

export const Alert = forwardRef<HTMLDivElement, AlertProps>(function Alert(props, ref) {
  const {
    title,
    type = 'info',
    description,
    closable = true,
    closeText,
    center = false,
    effect = 'light',
    showIcon = false,
    onClose,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('alert');
  const [visible, setVisible] = useState(true);

  const handleClose = (e: MouseEvent) => {
    setVisible(false);
    onClose?.(e);
  };

  if (!visible) return null;

  const classes = cls(
    ns.b(),
    ns.m(type),
    ns.m(effect),
    ns.is('center', center),
    ns.is('with-description', description != null || children != null),
    className,
  );

  const body = description ?? children;

  return (
    <div ref={ref} className={classes} role="alert" {...rest}>
      {showIcon && <TypeIcon type={type} className={ns.e('icon')} />}
      <div className={ns.e('content')}>
        {title != null && <span className={ns.e('title')}>{title}</span>}
        {body != null && <p className={ns.e('description')}>{body}</p>}
      </div>
      {closable &&
        (closeText ? (
          <button
            type="button"
            className={cls(ns.e('close-btn'), ns.is('customed'))}
            aria-label="Close"
            onClick={handleClose}
          >
            {closeText}
          </button>
        ) : (
          <button
            type="button"
            className={ns.e('close-btn')}
            aria-label="Close"
            onClick={handleClose}
          >
            <CloseIcon />
          </button>
        ))}
    </div>
  );
});

.ec-alert {
  --ec-alert-padding: 8px 16px;
  --ec-alert-border-radius: var(--ec-border-radius-base);
  --ec-alert-title-font-size: var(--ec-font-size-base);
  --ec-alert-description-font-size: var(--ec-font-size-small);
  --ec-alert-icon-size: 16px;
  --ec-alert-bg-color: var(--ec-color-info-light-9);
  --ec-alert-text-color: var(--ec-color-info);
  --ec-alert-border-color: var(--ec-color-info-light-8);

  display: flex;
  align-items: center;
  box-sizing: border-box;
  width: 100%;
  gap: 8px;
  padding: var(--ec-alert-padding);
  margin: 0;
  font-family: var(--ec-font-family);
  color: var(--ec-alert-text-color);
  background-color: var(--ec-alert-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-alert-border-color);
  border-radius: var(--ec-alert-border-radius);
  transition: var(--ec-transition-all);
}

.ec-alert.is-center {
  justify-content: center;
}

.ec-alert__icon {
  flex-shrink: 0;
  font-size: var(--ec-alert-icon-size);
  line-height: 1;
}

.ec-alert__content {
  display: flex;
  flex-direction: column;
  flex: 1;
  gap: 2px;
}

.ec-alert.is-center .ec-alert__content {
  flex: none;
  text-align: center;
}

.ec-alert__title {
  font-size: var(--ec-alert-title-font-size);
  line-height: 1.5;
  font-weight: var(--ec-font-weight-primary, 500);
  color: var(--ec-alert-text-color);
}

.ec-alert__description {
  margin: 0;
  font-size: var(--ec-alert-description-font-size);
  line-height: 1.5;
  color: var(--ec-alert-text-color);
}

.ec-alert__close-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  flex-shrink: 0;
  padding: 0;
  margin: 0;
  font-size: 14px;
  line-height: 1;
  color: inherit;
  cursor: pointer;
  background-color: transparent;
  border: none;
  border-radius: var(--ec-border-radius-small, 2px);
  outline: none;
  opacity: 0.85;
  transition: var(--ec-transition-all);
}

.ec-alert__close-btn.is-customed {
  font-size: var(--ec-alert-description-font-size);
}

.ec-alert__close-btn:hover {
  opacity: 1;
}

.ec-alert__close-btn:focus-visible {
  outline: 2px solid currentColor;
  outline-offset: 1px;
}

/* =========================================================
   Light effect (default): light-9 bg + accessible text + light-8 border

   The brand base color does not reach the WCAG 2.1 AA 4.5:1 contrast ratio
   against its own light-9 background. The component-scoped text tokens below
   mirror the Tag light-effect tokens (mix(black, base, 0.4)) so they clear
   4.5:1 on the corresponding light-9 background for every type. `error` shares
   the danger base color, so it reuses the danger-derived text color.
   ========================================================= */
.ec-alert--light {
  --ec-alert-light-text-success: #3e7423;
  --ec-alert-light-text-info: #56585c;
  --ec-alert-light-text-warning: #8a6124;
  --ec-alert-light-text-error: #934141;
}
.ec-alert--success.ec-alert--light {
  --ec-alert-bg-color: var(--ec-color-success-light-9);
  --ec-alert-text-color: var(--ec-alert-light-text-success);
  --ec-alert-border-color: var(--ec-color-success-light-8);
}
.ec-alert--info.ec-alert--light {
  --ec-alert-bg-color: var(--ec-color-info-light-9);
  --ec-alert-text-color: var(--ec-alert-light-text-info);
  --ec-alert-border-color: var(--ec-color-info-light-8);
}
.ec-alert--warning.ec-alert--light {
  --ec-alert-bg-color: var(--ec-color-warning-light-9);
  --ec-alert-text-color: var(--ec-alert-light-text-warning);
  --ec-alert-border-color: var(--ec-color-warning-light-8);
}
.ec-alert--error.ec-alert--light {
  --ec-alert-bg-color: var(--ec-color-error-light-9);
  --ec-alert-text-color: var(--ec-alert-light-text-error);
  --ec-alert-border-color: var(--ec-color-error-light-8);
}

/* =========================================================
   Dark effect: solid type bg + contrast text
   ========================================================= */
.ec-alert--success.ec-alert--dark {
  --ec-alert-bg-color: var(--ec-color-success);
  --ec-alert-text-color: var(--ec-color-success-contrast);
  --ec-alert-border-color: var(--ec-color-success);
}
.ec-alert--info.ec-alert--dark {
  --ec-alert-bg-color: var(--ec-color-info);
  --ec-alert-text-color: var(--ec-color-info-contrast);
  --ec-alert-border-color: var(--ec-color-info);
}
.ec-alert--warning.ec-alert--dark {
  --ec-alert-bg-color: var(--ec-color-warning);
  --ec-alert-text-color: var(--ec-color-warning-contrast);
  --ec-alert-border-color: var(--ec-color-warning);
}
.ec-alert--error.ec-alert--dark {
  --ec-alert-bg-color: var(--ec-color-error);
  --ec-alert-text-color: var(--ec-color-error-contrast);
  --ec-alert-border-color: var(--ec-color-error);
}

/* In the dark effect the title/description inherit the contrast text color. */
.ec-alert--dark .ec-alert__title,
.ec-alert--dark .ec-alert__description {
  color: var(--ec-alert-text-color);
}
